async function fetchPrFeedback(provider, issueId) {
  try {
    const prStatus = await provider.getPrStatus(issueId);
    if (!prStatus.url || prStatus.state === PrState.MERGED || prStatus.state === PrState.CLOSED) {
      return void 0;
    }
    const reviewComments = await provider.getPrReviewComments(issueId);
    if (reviewComments.length === 0) return void 0;
    const reason = prStatus.mergeable === false ? "merge_conflict" : prStatus.state === PrState.CHANGES_REQUESTED || prStatus.state === PrState.HAS_COMMENTS ? "changes_requested" : "rejected";
    return {
      url: prStatus.url,
      branchName: prStatus.sourceBranch,
      reason,
      comments: reviewComments.map((c) => ({
        id: c.id,
        author: c.author,
        body: c.body,
        state: c.state,
        path: c.path,
        line: c.line
      }))
    };
  } catch {
    return void 0;
  }
}
async function fetchPrContext(provider, issueId) {
  try {
    const prStatus = await provider.getPrStatus(issueId);
    if (!prStatus.url) return void 0;
    const diff = await provider.getPrDiff(issueId) ?? void 0;
    return { url: prStatus.url, diff };
  } catch {
    return void 0;
  }
}
function formatPrContext(prContext) {
  const parts = [``, `## Pull Request`, `\u{1F517} ${prContext.url}`];
  if (prContext.diff) {
    const maxDiffLen = 5e4;
    const diff = prContext.diff.length > maxDiffLen ? prContext.diff.slice(0, maxDiffLen) + "\n... (diff truncated, see PR for full changes)" : prContext.diff;
    parts.push(``, `### Diff`, "```diff", diff, "```");
  }
  return parts;
}
function formatPrFeedback(prFeedback, baseBranch) {
  if (prFeedback.comments.length === 0) return [];
  const reasonLabel = prFeedback.reason === "merge_conflict" ? "\u26A0\uFE0F Merge conflicts detected" : prFeedback.reason === "changes_requested" ? "\u26A0\uFE0F Changes were requested" : "\u26A0\uFE0F PR was rejected";
  const parts = [
    ``,
    `## PR Review Feedback`,
    `${reasonLabel}. Address the feedback below.`,
    `\u{1F517} ${prFeedback.url}`
  ];
  for (const c of prFeedback.comments) {
    const location = c.path ? ` (${c.path}${c.line ? `:${c.line}` : ""})` : "";
    parts.push(``, `**${c.author}** [${c.state}]${location}:`, c.body);
  }
  if (prFeedback.reason === "merge_conflict") {
    const branchName = prFeedback.branchName || "your-branch";
    parts.push(
      ``,
      `### Conflict Resolution Instructions`,
      ``,
      `**Important:** You must update the EXISTING PR branch, not create a new one.`,
      ``,
      `\u{1F539} PR: ${prFeedback.url}`,
      `\u{1F539} Branch: \`${branchName}\``,
      ``,
      `**Step-by-step:**`,
      ``,
      `1. Fetch and check out the PR branch:`,
      `   \`\`\`bash`,
      `   git fetch origin ${branchName}`,
      `   git checkout ${branchName}`,
      `   # Or if you already have a worktree:`,
      `   cd "${branchName}"`,
      `   git fetch origin`,
      `   git reset --hard origin/${branchName}`,
      `   \`\`\``,
      ``,
      `2. Rebase onto \`${baseBranch}\`:`,
      `   \`\`\`bash`,
      `   git rebase ${baseBranch}`,
      `   \`\`\``,
      ``,
      `3. Resolve any conflicts:`,
      `   - Edit conflicted files (marked with <<<<<<< and >>>>>>>)`,
      `   - \`git add <resolved-files>\``,
      `   - \`git rebase --continue\``,
      `   - Repeat until rebase completes`,
      ``,
      `4. Force-push to the SAME branch:`,
      `   \`\`\`bash`,
      `   git push --force-with-lease origin ${branchName}`,
      `   \`\`\``,
      ``,
      `5. Verify the PR shows as mergeable:`,
      `   \`\`\`bash`,
      `   gh pr view <PR-number>`,
      `   # Status should be "Mergeable" or "Open"`,
      `   \`\`\``,
      ``,
      `\u26A0\uFE0F Do NOT create a new PR. Do NOT switch branches. Update THIS PR only.`
    );
  }
  return parts;
}

