// lib/services/gateway-sessions.ts
import fs10 from "node:fs/promises";
async function fetchGatewaySessions(gatewayTimeoutMs = 15e3, runCommand) {
  const rc = runCommand;
  const lookup = /* @__PURE__ */ new Map();
  try {
    const result = await rc(
      ["openclaw", "gateway", "call", "status", "--json"],
      { timeoutMs: gatewayTimeoutMs }
    );
    const jsonStart = result.stdout.indexOf("{");
    const data = JSON.parse(jsonStart >= 0 ? result.stdout.slice(jsonStart) : result.stdout);
    const sessionPaths = data?.sessions?.paths ?? [];
    let readFromFiles = false;
    for (const filePath of sessionPaths) {
      try {
        const raw = await fs10.readFile(filePath, "utf-8");
        const fileData = JSON.parse(raw);
        for (const [key, entry] of Object.entries(fileData)) {
          if (key && !lookup.has(key)) {
            lookup.set(key, {
              key,
              updatedAt: entry.updatedAt ?? 0,
              percentUsed: entry.percentUsed ?? (entry.contextTokens && entry.totalTokens ? Math.round(entry.contextTokens / entry.totalTokens * 100) : 0),
              abortedLastRun: entry.abortedLastRun,
              totalTokens: entry.totalTokens,
              contextTokens: entry.contextTokens
            });
          }
        }
        readFromFiles = true;
      } catch {
      }
    }
    if (!readFromFiles) {
      const recentSessions = data?.sessions?.recent ?? [];
      for (const session of recentSessions) {
        if (session.key) {
          lookup.set(session.key, session);
        }
      }
    }
    return lookup;
  } catch {
    return null;
  }
}
function isSessionAlive(sessionKey, sessions) {
  return sessions ? sessions.has(sessionKey) : false;
}

