// lib/tools/tasks/research-task.ts
init_audit();
init_workflow();

// lib/roles/model-selector.ts
init_roles();
var SIMPLE_KEYWORDS = [
  "typo",
  "fix typo",
  "rename",
  "update text",
  "change color",
  "minor",
  "small",
  "css",
  "style",
  "copy",
  "wording"
];
var COMPLEX_KEYWORDS = [
  "architect",
  "refactor",
  "redesign",
  "system-wide",
  "migration",
  "database schema",
  "security",
  "performance",
  "infrastructure",
  "multi-service"
];
function selectLevel(issueTitle, issueDescription, role) {
  const levels = getLevelsForRole(role);
  const defaultLvl = getDefaultLevel(role);
  if (levels.length <= 1) {
    const level2 = levels[0] ?? defaultLvl ?? "medior";
    return { level: level2, reason: `Only level for ${role}` };
  }
  const text = `${issueTitle} ${issueDescription}`.toLowerCase();
  const wordCount = text.split(/\s+/).length;
  const isSimple = SIMPLE_KEYWORDS.some((kw) => text.includes(kw));
  const isComplex = COMPLEX_KEYWORDS.some((kw) => text.includes(kw));
  const lowest = levels[0];
  const highest = levels[levels.length - 1];
  if (levels.length === 2) {
    if (isComplex) {
      return { level: highest, reason: `Complex task \u2014 using ${highest}` };
    }
    return { level: lowest, reason: `Standard task \u2014 using ${lowest}` };
  }
  if (isSimple && wordCount < 100) {
    return {
      level: lowest,
      reason: `Simple task detected (keywords: ${SIMPLE_KEYWORDS.filter((kw) => text.includes(kw)).join(", ")})`
    };
  }
  if (isComplex || wordCount > 500) {
    return {
      level: highest,
      reason: `Complex task detected (${isComplex ? "keywords: " + COMPLEX_KEYWORDS.filter((kw) => text.includes(kw)).join(", ") : "long description"})`
    };
  }
  const level = defaultLvl ?? levels[Math.floor(levels.length / 2)];
  return { level, reason: `Standard ${role} task` };
}

