async function scanOrphanedLabels(opts) {
  const {
    workspaceDir,
    projectSlug,
    project,
    role,
    autoFix,
    provider,
    workflow = DEFAULT_WORKFLOW,
    instanceName
  } = opts;
  const fixes = [];
  if (!hasWorkflowStates(workflow, role)) return fixes;
  let freshProject;
  try {
    const data = await readProjects(workspaceDir);
    freshProject = getProject(data, projectSlug) ?? project;
  } catch {
    freshProject = project;
  }
  const roleWorker = getRoleWorker(freshProject, role);
  const activeLabel = getActiveLabel(workflow, role);
  const queueLabel = getRevertLabel(workflow, role);
  let issuesWithLabel;
  try {
    issuesWithLabel = await provider.listIssuesByLabel(activeLabel);
  } catch {
    return fixes;
  }
  const ownedIssues = instanceName ? issuesWithLabel.filter((i) => isOwnedByOrUnclaimed(i.labels, instanceName)) : issuesWithLabel;
  for (const issue2 of ownedIssues) {
    const issueIdStr = String(issue2.iid);
    let isTracked = false;
    for (const slots of Object.values(roleWorker.levels)) {
      if (slots.some((slot) => slot.active && slot.issueId === issueIdStr)) {
        isTracked = true;
        break;
      }
    }
    if (!isTracked) {
      const fix = {
        issue: {
          type: "orphaned_label",
          severity: "critical",
          project: project.name,
          projectSlug,
          role,
          issueId: issueIdStr,
          expectedLabel: queueLabel,
          actualLabel: activeLabel,
          message: `Issue #${issue2.iid} has "${activeLabel}" label but no ${role.toUpperCase()} slot is tracking it`
        },
        fixed: false
      };
      if (autoFix) {
        try {
          const revertTarget = await resolveOrphanRevertLabel(
            provider,
            issue2.iid,
            role,
            queueLabel,
            workflow
          );
          await provider.transitionLabel(issue2.iid, activeLabel, revertTarget);
          fix.fixed = true;
          fix.labelReverted = `${activeLabel} \u2192 ${revertTarget}`;
          fix.issue.expectedLabel = revertTarget;
        } catch {
          fix.labelRevertFailed = true;
        }
      }
      fixes.push(fix);
    }
  }
  return fixes;
}
async function scanStatelessIssues(opts) {
  const {
    workspaceDir,
    projectSlug,
    project,
    provider,
    workflow = DEFAULT_WORKFLOW,
    autoFix,
    instanceName
  } = opts;
  const fixes = [];
  const stateLabels = getStateLabels(workflow);
  const initialLabel = workflow.states[workflow.initial]?.label;
  if (!initialLabel) return fixes;
  let allOpenIssues;
  try {
    allOpenIssues = await provider.listIssues({ state: "open" });
  } catch {
    return fixes;
  }
  for (const issue2 of allOpenIssues) {
    const hasStateLabel = issue2.labels.some((l) => stateLabels.includes(l));
    if (hasStateLabel) continue;
    const hasWorkflowLabels = issue2.labels.some(
      (l) => l.startsWith("developer:") || l.startsWith("tester:") || l.startsWith("reviewer:") || l.startsWith("architect:") || l.startsWith("review:") || l.startsWith("test:") || l.startsWith("owner:") || l.startsWith("notify:")
    );
    if (!hasWorkflowLabels) continue;
    if (instanceName && !isOwnedByOrUnclaimed(issue2.labels, instanceName)) continue;
    const fix = {
      issue: {
        type: "stateless_issue",
        severity: "critical",
        project: project.name,
        projectSlug,
        role: "developer",
        issueId: String(issue2.iid),
        expectedLabel: initialLabel,
        actualLabel: null,
        message: `Issue #${issue2.iid} has no state label \u2014 invisible to queue scanner. Labels: [${issue2.labels.join(", ")}]`
      },
      fixed: false
    };
    if (autoFix) {
      try {
        await provider.ensureLabel(initialLabel, "");
        await provider.addLabel(issue2.iid, initialLabel);
        fix.fixed = true;
        fix.labelReverted = `(none) \u2192 ${initialLabel}`;
        await log(workspaceDir, "stateless_issue_recovered", {
          project: project.name,
          issueId: issue2.iid,
          restoredTo: initialLabel,
          originalLabels: issue2.labels
        });
      } catch {
        fix.labelRevertFailed = true;
      }
    }
    fixes.push(fix);
  }
  return fixes;
}

